(function () {
  function addStyle() { if (document.getElementById('ehc-style')) return; var s = document.createElement('style'); s.id = 'ehc-style'; s.textContent = '.ehc-wrap{border:1px solid #e5e7eb;border-radius:12px;padding:16px;background:#fff;margin:14px 0}.ehc-board{position:relative;height:280px;background:#f8fafc;border:1px solid #e5e7eb;border-radius:12px;margin:12px 0}.ehc-edge{position:absolute;height:4px;background:#cbd5e1;transform-origin:left center;border:0;cursor:pointer}.ehc-edge.on{background:#007bff}.ehc-node{position:absolute;width:44px;height:44px;border-radius:999px;background:#fff;border:2px solid #007bff;color:#007bff;display:flex;align-items:center;justify-content:center;font-weight:700;transform:translate(-50%,-50%);z-index:2}.ehc-actions{display:flex;gap:8px;flex-wrap:wrap}.ehc-out{margin-top:12px;padding:12px;border-radius:8px;background:#f8f9fa;line-height:1.7}.ehc-pill{display:inline-block;margin:3px;padding:5px 9px;border-radius:999px;background:#e8f4fd}'; document.head.appendChild(s); }
  function mount(host) { if (!host || host.dataset.ehcMounted) return; host.dataset.ehcMounted = '1'; addStyle(); var pts = [[50,12],[86,38],[72,82],[28,82],[14,38]], names = ['A','B','C','D','E'], edges = {'0-1':1,'1-2':1,'2-3':1,'3-4':1,'0-4':1}; host.innerHTML = '<div class="ehc-wrap"><h4>🧭 Kiểm tra Euler / Hamilton</h4><p>Nhấn cạnh để bật/tắt.</p><div class="ehc-board"></div><div class="ehc-actions"><button type="button" data-euler>Kiểm tra Euler</button><button type="button" data-hamilton>Kiểm tra Hamilton</button></div><div class="ehc-out"></div></div>'; var board = host.querySelector('.ehc-board'), out = host.querySelector('.ehc-out'); function key(i, j) { return Math.min(i, j) + '-' + Math.max(i, j); } function adj() { return names.map(function () { return []; }).map(function (a, i) { Object.keys(edges).forEach(function (k) { if (!edges[k]) return; var p = k.split('-').map(Number); if (p[0] === i) a.push(p[1]); if (p[1] === i) a.push(p[0]); }); return a; }); } function connected(a) { var seen = {}, stack = [0]; while (stack.length) { var u = stack.pop(); if (seen[u]) continue; seen[u] = 1; a[u].forEach(function (v) { stack.push(v); }); } return names.every(function (_, i) { return seen[i] || a[i].length === 0; }); } function hamilton(a) { function dfs(path) { if (path.length === names.length) return a[path[path.length - 1]].indexOf(path[0]) >= 0 ? path : null; var u = path[path.length - 1]; for (var i = 0; i < a[u].length; i++) if (path.indexOf(a[u][i]) < 0) { var r = dfs(path.concat(a[u][i])); if (r) return r; } return null; } for (var s0 = 0; s0 < names.length; s0++) { var r = dfs([s0]); if (r) return r; } return null; } function draw() { board.innerHTML = ''; for (var i = 0; i < 5; i++) for (var j = i + 1; j < 5; j++) { var p = pts[i], q = pts[j], dx = q[0] - p[0], dy = q[1] - p[1], e = document.createElement('button'); e.type = 'button'; e.className = 'ehc-edge ' + (edges[key(i, j)] ? 'on' : ''); e.style.left = p[0] + '%'; e.style.top = p[1] + '%'; e.style.width = Math.sqrt(dx * dx + dy * dy) + '%'; e.style.transform = 'rotate(' + Math.atan2(dy, dx) + 'rad)'; (function (a, b) { e.addEventListener('click', function () { edges[key(a, b)] = !edges[key(a, b)]; draw(); report('degree'); }); }(i, j)); board.appendChild(e); } pts.forEach(function (p, i) { var n = document.createElement('div'); n.className = 'ehc-node'; n.style.left = p[0] + '%'; n.style.top = p[1] + '%'; n.textContent = names[i]; board.appendChild(n); }); } function report(mode) { var a = adj(), deg = a.map(function (x, i) { return '<span class="ehc-pill">' + names[i] + ': bậc ' + x.length + '</span>'; }).join(''), msg = '<p>' + deg + '</p>'; if (mode === 'euler') msg += connected(a) && a.every(function (x) { return x.length % 2 === 0; }) ? '<strong>Có chu trình Euler.</strong>' : '<strong>Không có chu trình Euler.</strong> Cần liên thông và mọi bậc chẵn.'; if (mode === 'hamilton') { var h = hamilton(a); msg += h ? '<strong>Có chu trình Hamilton:</strong> ' + h.map(function (i) { return names[i]; }).join(' → ') + ' → ' + names[h[0]] : '<strong>Chưa tìm thấy chu trình Hamilton.</strong>'; } out.innerHTML = msg; } host.querySelector('[data-euler]').addEventListener('click', function () { report('euler'); }); host.querySelector('[data-hamilton]').addEventListener('click', function () { report('hamilton'); }); draw(); report('degree'); }
  document.addEventListener('DOMContentLoaded', function () { document.querySelectorAll('[data-demo="euler-hamilton-checker"]').forEach(mount); });
}());
